  const body = { status: 'ok' };
  if (process.env.NODE_ENV !== 'production') {
    body.timestamp = new Date().toISOString();
  }
  res.json(body);
});
```

---

#### 8. 🟡 No Async Error Propagation Guard
If any route handlers become `async` in the future, unhandled promise rejections won't be passed to your error middleware unless you explicitly `catch` them.

**Fix (Express 4):** Wrap async handlers or use a helper:
```js
const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);

app.get('/users', asyncHandler(async (req, res) => {
  // any thrown error is forwarded to the global error handler
  const users = await fetchUsersFromDB();
  res.json(users);
}));
```
> Note: Express 5 handles this automatically.

---

