### 2. 🛡️ Add Security Headers via `helmet`
HTTP response headers can leak server info and enable attacks (XSS, clickjacking, etc.). [`helmet`](https://helmetjs.github.io/) sets safe defaults in one line:

```js
const helmet = require('helmet');
app.use(helmet());
```

---

### 3. 🚦 Add a Global Error-Handling Middleware
Currently, unhandled errors will crash routes or produce unformatted responses. A centralized error handler prevents leaking stack traces to clients:

```js
// Place AFTER all routes
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message, // Only show details in dev
  });
});
```

---

### 4. 🔍 Add a 404 Handler for Unknown Routes
Unknown routes currently fall through silently. Explicitly handle them:

```js
// Place BEFORE the error handler, AFTER all routes
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});
```

---

### 5. 🔐 Add Rate Limiting
The `/users` endpoint (and any future ones) are wide open to abuse. Use [`express-rate-limit`](https://github.com/express-rate-limit/express-rate-limit):

```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // Max 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 6. 📦 Validate Query Parameters (Input Validation)
Even on GET routes, query parameters (e.g., `?id=`, `?page=`) should be validated before use. A common lightweight option is [`express-validator`](https://express-validator.github.io/):

```js
const { query, validationResult } = require('express-validator');

app.get('/users', [
  query('page').optional().isInt({ min: 1 }).toInt(),
  query('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  // ... proceed
});
```

---

### 7. 🌐 Harden the `listen` Call
Avoid binding to all interfaces in production (`0.0.0.0` is the default). Prefer explicit host binding and handle startup errors:

```js
const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || '127.0.0.1';

const server = app.listen(PORT, HOST, () => {
  console.log(`Server running on ${HOST}:${PORT}`);
});

server.on('error', (err) => {
  console.error('Server failed to start:', err);
  process.exit(1);
});
```

